import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v13 (Islam - major institutions) ===');

w('profiles_v13','saudi-wahhabi-establishment',{"brand_name":"Saudi Wahhabi Establishment","brand_slug":"saudi-wahhabi-establishment","parent_company":"Kingdom of Saudi Arabia / Ministry of Islamic Affairs","ultimate_parent":"Al Saud royal family","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"SAUDI ARABIA HAS EXPORTED AN ESTIMATED $75-100 BILLION IN WAHHABI RELIGIOUS FUNDING SINCE 1975 — 15 OF THE 19 SEPTEMBER 11 HIJACKERS WERE SAUDI — AND THE '28 PAGES' DOCUMENTED SAUDI GOVERNMENT CONNECTIONS TO THE PLOT","executive_summary":"The Saudi Wahhabi establishment represents the intersection of the Al Saud royal family's political authority and the Wahhabi religious movement founded by Muhammad ibn Abd al-Wahhab in the 18th century — a puritanical Sunni Islamic doctrine that became the state religion of Saudi Arabia. Since the 1973 oil embargo generated massive petroleum wealth, Saudi Arabia has exported an estimated $75-100 billion in religious funding globally — building mosques, madrassas, and Islamic centers, funding scholars, and distributing religious literature promoting Wahhabi/Salafi interpretations of Islam in over 100 countries. The 9/11 Commission documented that 15 of the 19 hijackers were Saudi nationals. Declassified portions of the 28-page section of the Joint Congressional Inquiry into 9/11 (released 2016) documented connections between Saudi government officials and some hijackers. The Saudi government paid $1 billion in 2016 in the first US payments to 9/11 victims' families — without admitting responsibility.","verdict_tags":["75_100b_wahhabi_funding_exported_estimated","15_of_19_hijackers_saudi_nationals","28_pages_saudi_government_connections_documented","1b_2016_payments_9_11_families","global_mosque_madrassa_funding_100_countries","jamal_khashoggi_assassination_cia_mbs_ordered","khashoggi_1b_cia_mbs_ordered","no_us_terrorism_designation"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":false,"health":false,"legal":true},"labor":{"summary":"Saudi Arabia's kafala system — under which migrant workers are legally bound to their employers and cannot change jobs or leave the country without employer permission — has been documented by Human Rights Watch, Amnesty International, and UN bodies as creating conditions of forced labor and modern slavery for millions of domestic and construction workers. An estimated 10-13 million migrant workers work in Saudi Arabia under kafala.","flags":["kafala_forced_labor_10_13_million_migrants","hrw_amnesty_un_documented","cannot_change_jobs_leave_without_permission"],"sources":["https://www.hrw.org/report/2008/07/07/locked-box/isolation-and-abuse-domestic-workers-saudi-arabia"]},"environmental":{"summary":"Saudi Arabia is the world's largest oil exporter and the de facto leader of OPEC — whose output decisions directly affect global greenhouse gas emissions. Saudi Aramco is the world's most profitable company and among the largest single contributors to global carbon emissions. The Saudi state's oil revenues fund the religious establishment that is the subject of this profile.","flags":["largest_oil_exporter_aramco","opec_output_decisions_greenhouse_effect","oil_revenues_fund_religious_establishment"],"sources":[]},"political":{"summary":"The Wahhabi establishment's global funding — documented by the 9/11 Commission, the US Department of State, and multiple Western intelligence agencies — has promoted an intolerant interpretation of Islam that has been linked to radicalization in multiple countries. The declassified 28 pages of the Joint Congressional Inquiry documented connections between Saudi government officials (including then-Ambassador Prince Bandar bin Sultan's wife's charitable payments) and two hijackers. CIA Director Gina Haspel's assessment — provided to the Biden administration in 2021 — concluded that Saudi Crown Prince Mohammed bin Salman approved the operation to capture or kill journalist Jamal Khashoggi, who was subsequently murdered and dismembered in the Saudi consulate in Istanbul in October 2018.","flags":["9_11_commission_global_funding_documented","28_pages_government_official_connections","cia_mbs_khashoggi_murder_approved","khashoggi_istanbul_consulate_murdered_dismembered_2018","state_department_radicalization_link_documented"],"sources":["https://www.dni.gov/files/ODNI/documents/assessments/Assessment-Saudi-Gov-Role-in-JK-Death-20210226v2.pdf"]},"legal":{"summary":"The Justice Against Sponsors of Terrorism Act (JASTA, 2016) allows US citizens to sue foreign governments for acts of terrorism on US soil — enabling 9/11 victims' families to sue Saudi Arabia. Saudi Arabia reached settlements with families totaling approximately $1 billion in 2016 without admitting responsibility. The 28-page section of the Joint Congressional Inquiry — classified for 15 years and released in 2016 — documented connections between Saudi government officials and some hijackers without establishing direct government authorization. Jamal Khashoggi: the Biden administration's CIA assessment concluded MBS approved the operation; the US imposed sanctions on some involved individuals but not on MBS himself.","flags":["jasta_2016_enables_family_suits","1b_settlements_no_admission","28_pages_released_2016_connections_documented","cia_mbs_assessment_sanctions_not_on_mbs"],"sources":["https://www.dni.gov/files/ODNI/documents/assessments/Assessment-Saudi-Gov-Role-in-JK-Death-20210226v2.pdf"]},"tax":{"summary":"The Saudi Wahhabi establishment's global funding operates through the Saudi government, the Muslim World League, and hundreds of Saudi-funded charitable organizations globally — many of which are registered as nonprofits in their host countries and receive charitable tax benefits. The financial flows are not publicly disclosed in any comprehensive way; estimates of $75-100 billion since 1975 are based on research by scholars including Rand Corporation analysts and former US officials.","flags":["muslim_world_league_primary_vehicle","global_charitable_registration_tax_benefits","75_100b_estimate_based_research"],"sources":[]},"executives":{"summary":"Crown Prince Mohammed bin Salman (MBS) is the de facto ruler of Saudi Arabia and the primary decision-maker in the kingdom's religious, political, and economic affairs. The CIA assessment concluded he approved the killing of Jamal Khashoggi. The Grand Mufti — currently Sheikh Abdulaziz Al Sheikh — is the highest religious authority in the kingdom. The Ministry of Islamic Affairs controls the Wahhabi religious establishment's global funding apparatus.","flags":["mbs_cia_khashoggi_approved","grand_mufti_al_sheikh","ministry_islamic_affairs_controls_global_funding"],"sources":[]},"connections":{"summary":"The Wahhabi establishment's funded network is documented as having contributed to the ideological formation of Al Qaeda, ISIS, and other Salafi-jihadist movements — though direct organizational connections are contested and the majority of Wahhabi-influenced Muslims do not engage in political violence. The Taliban's religious ideology (Deobandism) is distinct from Wahhabism but shares a puritanical framework. Saudi funding of madrassas in Pakistan has been documented as contributing to radicalization pipelines.","flags":["al_qaeda_isis_ideological_connection_contested","pakistan_madrassa_funding_radicalization_documented","majority_wahhabi_not_violent_clarification"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former US officials and terrorism researchers have alleged that Saudi charities and government-adjacent organizations knowingly funded organizations with connections to terrorism financing — not merely inadvertently promoting radical ideology through educational materials. The 28 pages documented specific connections without establishing direct government authorization at the highest levels. Saudi Arabia disputes that its government or senior officials deliberately facilitated the September 11 attacks.","flags":["knowing_terrorism_financing_alleged_former_officials","28_pages_connections_not_authorization","saudi_denial_deliberate_facilitation"],"sources":[]},"health_record":{"summary":"The kafala system's documented conditions — forced labor, inability to leave employment, physical abuse of domestic workers, deaths in construction (documented at FIFA World Cup Qatar preparations, where similar Gulf state systems apply) — represent direct health harm to millions of migrant workers. The Wahhabi religious export's documented contribution to radicalization environments has downstream violence connections that are documented but causally complex.","flags":["kafala_migrant_worker_physical_abuse_deaths","qatari_world_cup_parallel_gulf_state","radicalization_violence_downstream_documented"],"sources":[]},"alternatives":{"cheaper":["No direct consumer alternative — Saudi Arabia is a state actor","Supporting human rights organizations documenting kafala: Human Rights Watch, Migrant-Rights.org"],"healthier":["Amnesty International's documentation of kafala abuses","Human Rights Watch reports on Saudi migrant worker conditions"],"diy":["The declassified 28 pages are publicly available through the DNI","The CIA Khashoggi assessment is publicly available at dni.gov"]},"timeline":[{"year":1744,"event":"Muhammad ibn Abd al-Wahhab and Muhammad ibn Saud form the alliance that founds the Saudi-Wahhabi pact — the foundation of modern Saudi Arabia","severity":"neutral","source_url":""},{"year":1973,"event":"Oil embargo generates massive petroleum wealth; Saudi Arabia begins systematic global Wahhabi religious funding expansion","severity":"critical","source_url":""},{"year":2001,"event":"September 11: 15 of 19 hijackers are Saudi nationals; 9/11 Commission subsequently documents global Wahhabi funding concerns","severity":"critical","source_url":""},{"year":2002,"event":"Joint Congressional Inquiry completed; 28-page section on Saudi connections classified by Bush administration","severity":"critical","source_url":""},{"year":2016,"event":"28 pages declassified and released; JASTA passes allowing families to sue Saudi Arabia; $1B in settlements without Saudi admission","severity":"critical","source_url":""},{"year":2018,"event":"October: Jamal Khashoggi murdered and dismembered in Saudi consulate in Istanbul; CIA subsequently concludes MBS approved the operation","severity":"critical","source_url":""},{"year":2021,"event":"Biden administration releases CIA assessment concluding MBS approved Khashoggi operation; imposes sanctions on participants but not MBS","severity":"critical","source_url":"https://www.dni.gov/files/ODNI/documents/assessments/Assessment-Saudi-Gov-Role-in-JK-Death-20210226v2.pdf"}],"community_impact":{"displacement":"Migrant workers in Saudi Arabia under the kafala system — approximately 10-13 million people — cannot legally leave their employment or the country without employer permission. Documented abuses include confiscation of passports, non-payment of wages, physical abuse, and deaths in dangerous working conditions. Muslim communities globally who received Saudi-funded religious education have been documented to have received materials promoting intolerant interpretations of Islam inconsistent with their traditional local practices.","price_illusion":"Saudi Arabia presents its religious funding as charitable Islamic outreach — spreading authentic Islam. Western intelligence assessments document that the specific interpretations spread (Wahhabi/Salafi) have contributed to radicalization environments globally. The oil that funds this outreach is purchased by global consumers and governments.","tax_math":"Saudi Arabia is a state — standard corporate tax analysis does not apply. Its oil revenues fund the religious establishment. Global recipients of Saudi religious funding often register as nonprofits receiving charitable tax benefits in their host countries.","wealth_velocity":"The Al Saud royal family controls one of the world's largest sovereign wealth funds (PIF, approximately $700 billion) funded by Saudi Aramco's oil revenues. This wealth funds both the religious establishment and MBS's Vision 2030 economic diversification program."},"cost_absorption":{"who_benefited":[{"group":"Al Saud royal family","how":"Political legitimacy purchased through religious establishment support; oil revenues fund both"},{"group":"Wahhabi religious scholars and institutions globally","how":"$75-100B in funding since 1975 building global network of mosques, madrassas, and Islamic centers"}],"who_paid":[{"group":"10-13 million kafala migrant workers","how":"Forced labor conditions; inability to leave employment; physical abuse documented"},{"group":"9/11 victims and families","how":"15 of 19 hijackers were Saudi; 28 pages documented government connections; $1B settlements reached without Saudi admission"},{"group":"Jamal Khashoggi","how":"CIA assessment: MBS approved the operation; murdered and dismembered in Istanbul consulate"}],"the_gap":"Saudi Arabia has exported an estimated $75-100 billion in Wahhabi religious funding since 1975. 15 of the 19 September 11 hijackers were Saudi. The US classified the relevant 28 pages for 15 years. When they were released they documented connections between Saudi government officials and some hijackers. Jamal Khashoggi wrote critically about the Saudi government. He walked into the Saudi consulate in Istanbul in 2018. The CIA concluded the Crown Prince approved what happened to him. The US sanctioned the people who did it. Not the Crown Prince. Saudi Arabia settled with 9/11 families for $1 billion. They did not admit responsibility."}});

w('profiles_v13','muslim-brotherhood',{"brand_name":"Muslim Brotherhood","brand_slug":"muslim-brotherhood","parent_company":"Muslim Brotherhood (Al-Ikhwan Al-Muslimun)","ultimate_parent":"General Guidance Office, Muslim Brotherhood","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"THE MUSLIM BROTHERHOOD FOUNDED HAMAS AND IS DESIGNATED A TERRORIST ORGANIZATION BY EGYPT, SAUDI ARABIA, AND THE UAE — THE US HAS DEBATED DESIGNATION FOR DECADES WITHOUT ACTING — ITS POLITICAL ISLAM MODEL HAS SHAPED GOVERNMENTS ACROSS THE MIDDLE EAST","executive_summary":"The Muslim Brotherhood (Ikhwan) was founded in Egypt in 1928 by Hassan al-Banna as an Islamic revivalist organization combining religious education, social services, and political activism. It is the world's oldest and most influential Islamist political movement — with affiliated or inspired organizations across the Middle East, North Africa, Europe, and North America. Hamas — which governs Gaza and is designated a terrorist organization by the United States, European Union, and others — was founded as the Palestinian branch of the Muslim Brotherhood. The Brotherhood itself is designated a terrorist organization by Egypt, Saudi Arabia, the UAE, Russia, and several other countries but not by the United States or the European Union. The Brotherhood has participated in electoral politics in Egypt, Jordan, Tunisia, and Morocco — and briefly controlled the Egyptian government under President Mohamed Morsi (2012-2013) before being ousted in a military coup. The Trump administration considered but did not pursue US terrorist designation; the Biden administration did not pursue designation.","verdict_tags":["hamas_founded_as_mb_offshoot","designated_terrorist_egypt_saudi_uae_not_us_eu","morsi_egypt_president_2012_2013_military_coup","banna_founded_1928_egypt","sayyid_qutb_ideological_influence_al_qaeda","us_designation_debated_not_pursued","qatar_documented_mb_supporter","ikhwan_social_services_electoral_political_model"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":false,"legal":true},"labor":{"summary":"The Muslim Brotherhood's network of affiliated organizations has historically operated extensive social services — schools, clinics, and charitable organizations — particularly in Egypt and Gaza. These operations employ significant numbers of people in their operating countries. No major documented systemic Western labor violations have been identified in Brotherhood-affiliated organizations operating in Europe or North America.","flags":["social_services_network_schools_clinics_employment","affiliated_organizations_regional_employment"],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for the Muslim Brotherhood at the movement level.","flags":[],"sources":[]},"political":{"summary":"The Brotherhood's political model — using elections, social services, and Islamic identity to build political power — has influenced Islamist movements globally. Key documented political activities: In Egypt, the Brotherhood was banned, legalized, won parliamentary elections, and was ousted in military coups across multiple cycles. Mohamed Morsi's presidency (2012-2013) ended when General Abdel Fattah el-Sisi led a military coup; Morsi later died in custody in 2019. In Gaza, Hamas won the 2006 Palestinian legislative elections and has governed Gaza since 2007. Qatar has been documented as the Brotherhood's primary state supporter — providing funding, housing to Brotherhood leaders, and Al Jazeera's platform for Brotherhood-aligned perspectives. The Brotherhood's relationship with violence is contested: the organization's official position is nonviolence in most contexts, while Hamas (its Palestinian branch) conducts armed operations classified as terrorism by Western governments.","flags":["hamas_2006_elections_won_gaza_governed","qatar_primary_state_supporter_documented","morsi_death_custody_2019","egyptian_military_coup_sisi","nonviolence_official_position_hamas_violence_offshoot"],"sources":[]},"legal":{"summary":"Hamas — founded as the Palestinian Muslim Brotherhood — is designated a terrorist organization by the United States, European Union, UK, Canada, Australia, and others. The Muslim Brotherhood itself is designated by Egypt, Saudi Arabia, UAE, Russia, Bahrain, and others but not by the US or EU. The Holy Land Foundation case (2008): US prosecutors designated several US Islamic organizations as unindicted co-conspirators in Hamas fundraising — including some with Brotherhood connections. The Council on American-Islamic Relations (CAIR) was named as an unindicted co-conspirator; CAIR disputed the designation's accuracy and fairness. Morsi: died in Egyptian custody in June 2019 during a court hearing; UN experts called for investigation into his death as a possible arbitrary killing.","flags":["hamas_us_eu_uk_designated","ikhwan_egypt_saudi_uae_not_us_eu","holy_land_foundation_case_co_conspirator_designations","morsi_death_custody_un_investigation_call"],"sources":["https://www.justice.gov/archive/usao-ndtx/holyland.html"]},"tax":{"summary":"The Muslim Brotherhood operates as a transnational movement without a single corporate structure subject to standard tax analysis. Its affiliated organizations in Western countries are typically registered as Islamic charities or cultural organizations with nonprofit status in their host countries. Qatar's documented financial support flows through both government channels and private Qatari donors.","flags":["transnational_no_single_structure","western_affiliates_nonprofit_registered","qatar_government_private_donor_flows"],"sources":[]},"executives":{"summary":"The Muslim Brotherhood's General Guidance Office — based primarily in Qatar since the Egyptian crackdown following the 2013 coup — provides overall direction. Ibrahim Munir led the Brotherhood as Acting General Guide until his death in 2022. Hassan al-Banna, the founder, was assassinated by Egyptian government agents in 1949. Sayyid Qutb — whose writings while imprisoned in Egypt developed the concept of takfir (declaring other Muslims apostates) and provided ideological underpinning for Al Qaeda — was executed by the Egyptian government in 1966. Qutb's ideology is considered by scholars to represent a radicalization of the Brotherhood's original framework that most current Brotherhood leadership has officially disavowed.","flags":["qutb_takfir_al_qaeda_ideological_influence","banna_assassinated_1949","qatar_guidance_office_post_coup","munir_died_2022"],"sources":[]},"connections":{"summary":"Hamas is the most direct documented connection between the Muslim Brotherhood and designated terrorist violence. Al Qaeda's ideological lineage includes Qutb's Brotherhood-influenced writings — though Al Qaeda's leadership rejected the Brotherhood's electoral participation as apostasy. ISIS similarly drew on Qutb while rejecting Brotherhood electoral politics. The Brotherhood's affiliated or inspired organizations include: Ennahda (Tunisia), Justice and Development Party (Morocco), Hamas (Palestine), and others — spanning a spectrum from fully democratic electoral participation to armed resistance.","flags":["hamas_direct_branch","qutb_al_qaeda_ideological_lineage","ennahda_tunisia_jdp_morocco_affiliated","spectrum_democratic_to_armed"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Some US counterterrorism officials and researchers have alleged that the Brotherhood's 'nonviolence' position is tactical rather than principled — that it supports violence through affiliated organizations (Hamas) while maintaining a clean official position in Western contexts. Other researchers argue the Brotherhood represents legitimate Islamist political participation and should not be conflated with jihadist terrorism. The Brotherhood disputes characterizations linking it to terrorism beyond the Hamas connection, which it frames as resistance to occupation.","flags":["tactical_nonviolence_alleged_some_researchers","legitimate_political_participation_argument_others","hamas_resistance_not_terrorism_brotherhood_framing"],"sources":[]},"health_record":{"summary":"Hamas — the Brotherhood's Palestinian branch — has conducted documented terrorist attacks including suicide bombings, rocket attacks on Israeli civilian areas, and the October 7, 2023 attack that killed approximately 1,200 Israelis and resulted in the taking of approximately 250 hostages. The subsequent Israeli military response has killed tens of thousands of Palestinians in Gaza. These are documented facts about a Brotherhood offshoot; the Brotherhood's overall relationship to this violence is the subject of the contested analyses documented in the allegations section.","flags":["hamas_october_7_2023_1200_killed_250_hostages","israeli_response_tens_thousands_palestinian_deaths","brotherhood_offshoot_violence_relationship_contested"],"sources":[]},"alternatives":{"cheaper":["Mainstream Sunni Muslim organizations that do not have terrorist-designated offshoots"],"healthier":["Muslim organizations with clear doctrinal rejection of violence in all contexts"],"diy":["The Holy Land Foundation trial documents — including the unindicted co-conspirator designations — are public court records","The 9/11 Commission report includes extensive analysis of Brotherhood-Al Qaeda ideological connections"]},"timeline":[{"year":1928,"event":"Hassan al-Banna founds Muslim Brotherhood in Ismailia, Egypt","severity":"neutral","source_url":""},{"year":1949,"event":"Hassan al-Banna assassinated by Egyptian government agents","severity":"high","source_url":""},{"year":1966,"event":"Sayyid Qutb executed by Egyptian government; his writings become foundational to Salafi-jihadist movement","severity":"critical","source_url":""},{"year":1987,"event":"Hamas founded in Gaza as Palestinian branch of the Muslim Brotherhood","severity":"critical","source_url":""},{"year":2006,"event":"Hamas wins Palestinian legislative elections; governs Gaza since 2007","severity":"high","source_url":""},{"year":2012,"event":"Mohamed Morsi (Muslim Brotherhood) elected President of Egypt","severity":"high","source_url":""},{"year":2013,"event":"Military coup ousts Morsi; Egypt designates Muslim Brotherhood terrorist organization; Gulf states follow","severity":"critical","source_url":""},{"year":2019,"event":"Morsi dies in Egyptian custody during court hearing; UN experts call for investigation","severity":"critical","source_url":""},{"year":2023,"event":"October 7: Hamas attack kills approximately 1,200 Israelis; 250 hostages taken; Israeli military response kills tens of thousands in Gaza","severity":"critical","source_url":""}],"community_impact":{"displacement":"Palestinians living in Gaza under Hamas (Muslim Brotherhood) governance have experienced documented restrictions on civil liberties, political opposition, and women's rights alongside the humanitarian consequences of the Israeli blockade and military operations. Israeli civilians have experienced documented terrorism from Hamas. The Brotherhood's model — winning elections then restricting civil society — was documented during Morsi's brief Egyptian presidency.","price_illusion":"The Muslim Brotherhood presents as an Islamic social services and democratic political organization — 'Islam is the solution' is its historic slogan. Its record includes founding Hamas, providing the ideological precursor to Al Qaeda (through Qutb), governing Gaza in ways that restrict civil society, and participating in elections while restricting democratic opposition when in power.","tax_math":"The Brotherhood's Western-affiliated organizations are registered as nonprofits in their host countries. Qatar's documented financial support operates through both government and private channels that benefit from charitable tax frameworks in some jurisdictions.","wealth_velocity":"Qatar's documented financial support for the Brotherhood — including housing Brotherhood leaders in Doha — represents state wealth deployed for political influence. The Brotherhood's social service networks in Egypt and Gaza have historically been funded through charitable donations from Gulf state sources."},"cost_absorption":{"who_benefited":[{"group":"Muslim Brotherhood political networks","how":"Qatar financial and diplomatic support; Al Jazeera platform; governments in Egypt (briefly), Gaza, and elsewhere"},{"group":"Hamas","how":"Founded as MB offshoot; governs Gaza; receives Iranian and Qatari support"}],"who_paid":[{"group":"Israeli civilians killed and taken hostage October 7 2023","how":"Hamas attack killed approximately 1,200 people; 250 taken hostage"},{"group":"Palestinian civilians in Gaza","how":"Tens of thousands killed in Israeli military response following October 7; Hamas governance restricts civil liberties"},{"group":"Mohamed Morsi","how":"Died in Egyptian custody in 2019; UN experts called for investigation"}],"the_gap":"The Muslim Brotherhood founded Hamas. Hamas killed approximately 1,200 Israelis on October 7, 2023 and took 250 hostages. The Israeli military response has killed tens of thousands of Palestinians. The Brotherhood's ideological tradition produced Sayyid Qutb whose writings shaped Al Qaeda. Egypt, Saudi Arabia, and the UAE designate the Brotherhood as a terrorist organization. The US and EU do not. Qatar houses Brotherhood leadership. Mohamed Morsi died in an Egyptian prison. The Brotherhood says it supports democracy. It governed Egypt briefly and Gaza continuously through Hamas."}});

w('profiles_v13','nation-of-islam',{"brand_name":"Nation of Islam","brand_slug":"nation-of-islam","parent_company":"Nation of Islam","ultimate_parent":"Louis Farrakhan (Minister/Leader)","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"LOUIS FARRAKHAN HAS CALLED JUDAISM A 'GUTTER RELIGION,' CALLED HITLER 'A VERY GREAT MAN,' AND COMPARED JEWISH PEOPLE TO TERMITES — THE SPLC DESIGNATES NOI A HATE GROUP — AND MULTIPLE US POLITICIANS HAVE DOCUMENTED RELATIONSHIPS WITH FARRAKHAN","executive_summary":"The Nation of Islam (NOI) is a Black nationalist religious movement founded in Detroit in 1930 by Wallace D. Fard Muhammad, who taught a theology radically different from mainstream Islam — including the belief that white people were created by a scientist named Yakub as a race of devils, and that Black people are the original people of the Earth. Under its most prominent leader Elijah Muhammad (1934-1975) and his successor Louis Farrakhan (who reorganized the NOI after a schism with Warith Deen Mohammed), the NOI built a significant community infrastructure including the Final Call newspaper, restaurants, farms, and educational institutions. The Southern Poverty Law Center designates the NOI as a hate group for its documented antisemitic statements. Farrakhan has called Judaism a 'gutter religion' (1984), called Hitler 'a very great man' (1984), compared Jewish people to termites (2018), and made sustained documented statements characterizing Jewish people as controlling the media, Hollywood, and the US government. Despite this record, Farrakhan has maintained documented relationships with elected officials including US Representatives.","verdict_tags":["farrakhan_gutter_religion_1984","farrakhan_hitler_great_man_1984","farrakhan_jewish_termites_2018","splc_hate_group_designation","elijah_muhammad_yakub_theology","malcolm_x_assassination_noi_connection","million_man_march_1995","politicians_documented_farrakhan_relationships"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"The Nation of Islam operates a network of businesses, farms, and educational institutions employing community members. No major documented systemic labor violations have been identified beyond the organization's documented hate group status.","flags":["business_farm_educational_network_employment"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against the NOI have been identified.","flags":[],"sources":[]},"political":{"summary":"The NOI's political influence is disproportionate to its estimated 50,000-500,000 membership (estimates vary widely). The Million Man March (1995) — organized by Farrakhan — drew hundreds of thousands to Washington DC. Farrakhan's documented relationships with politicians who later distanced themselves include: Rep. Keith Ellison (D-MN, later Minnesota Attorney General), Rep. Maxine Waters (D-CA), and others who attended or met with Farrakhan. The Obama administration's longstanding relationship with Rev. Jeremiah Wright — who has documented NOI connections — generated significant political controversy. Farrakhan has also maintained documented relationships with Iranian leadership and traveled to Iran multiple times.","flags":["million_man_march_hundreds_thousands","politicians_ellison_waters_documented_then_distanced","farrakhan_iran_relationship_documented","obama_wright_noi_connections_controversy"],"sources":[]},"legal":{"summary":"Malcolm X — the NOI's most prominent figure until his break with Elijah Muhammad — was assassinated in 1965. Three NOI members were convicted of the murder. The 2021 exoneration of two of the three convicted men — Muhammad Aziz and Khalil Islam — raised questions about the adequacy of the original prosecution. A 2021 Manhattan DA investigation into the assassination found law enforcement intelligence failures and that evidence pointing to NOI involvement had been suppressed. Farrakhan's statements — including calling Jewish people termites — have been documented but have not resulted in criminal charges as protected speech. Facebook removed Farrakhan from its platform in 2019 under its policy against dangerous individuals.","flags":["malcolm_x_assassination_noi_members_convicted","2021_exoneration_two_convicted","da_investigation_suppressed_evidence","farrakhan_facebook_removed_2019","antisemitism_statements_protected_speech_not_charged"],"sources":["https://www.nytimes.com/2021/11/18/nyregion/malcolm-x-murder-exoneration.html"]},"tax":{"summary":"The Nation of Islam is registered as a religious organization and claims tax exemption. The Final Call newspaper — the NOI's publication — is operated as a separate entity. NOI businesses and farms operate as commercial entities with their own tax treatment. No major tax enforcement actions against the NOI have been identified.","flags":["religious_tax_exemption_claimed","final_call_separate_entity","businesses_farms_commercial_treatment"],"sources":[]},"executives":{"summary":"Louis Farrakhan has led the Nation of Islam since reorganizing it in 1977-1978 following the schism with Warith Deen Mohammed. Warith Deen Mohammed — son of Elijah Muhammad — moved the NOI toward mainstream Sunni Islam; Farrakhan maintained the original NOI theology. Farrakhan is in his late 80s and has had documented serious health issues. The succession question is unresolved. Elijah Muhammad — who led the NOI from 1934 to 1975 — fathered children with at least seven women outside his marriage; Malcolm X's public acknowledgment of this was a factor in the break between them.","flags":["farrakhan_late_80s_health_issues_succession_unclear","elijah_muhammad_outside_children_seven_women","malcolm_x_break_over_elijah_conduct"],"sources":[]},"connections":{"summary":"The NOI's connections to mainstream Black American political and religious life have been more extensive than its hate group designation suggests — Farrakhan maintained relationships with civil rights figures and politicians who later publicly distanced themselves. Its theology is distinct from mainstream Islam; the Council on American-Islamic Relations and mainstream Muslim organizations do not endorse the NOI's racial theology or Farrakhan's antisemitic statements.","flags":["civil_rights_figure_relationships_documented","mainstream_muslim_orgs_no_endorsement","cair_no_endorsement"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Malcolm X's family and advocates have alleged that the NOI's leadership — including members with documented connections to Farrakhan's organization — was responsible for ordering Malcolm X's assassination, and that law enforcement intelligence about this was suppressed from the defense at trial. The 2021 Manhattan DA investigation found law enforcement failures without conclusively establishing who ordered the killing.","flags":["noi_leadership_ordered_assassination_alleged","law_enforcement_suppression_documented_da_investigation","conclusive_finding_not_made"],"sources":["https://www.nytimes.com/2021/11/18/nyregion/malcolm-x-murder-exoneration.html"]},"health_record":{"summary":"The NOI's documented antisemitic statements — including characterizing Jewish people as termites and as controlling media and government — contribute to antisemitic prejudice in documented ways. The specific statements made by Farrakhan are among the most documented examples of prominent American antisemitism in recent decades. The ADL and SPLC have documented the NOI's antisemitism extensively. The NOI's racial theology — teaching that white people are a race of devils created by the scientist Yakub — similarly documents a hate ideology targeting white people.","flags":["antisemitism_documented_adl_splc_extensively","termites_hitler_gutter_religion_documented","racial_theology_anti_white_documented"],"sources":[]},"alternatives":{"cheaper":["Mainstream Sunni Muslim organizations — ISNA, ICNA — without hate group designation","Warith Deen Mohammed's movement — the American Society of Muslims — which moved to mainstream Sunni Islam"],"healthier":["Muslim American organizations without documented antisemitism and racial theology","Black American Muslim communities aligned with mainstream Sunni Islam"],"diy":["SPLC's NOI file documents specific statements with citations","ADL's documentation of Farrakhan's statements is publicly available"]},"timeline":[{"year":1930,"event":"Wallace D. Fard Muhammad founds the Nation of Islam in Detroit","severity":"neutral","source_url":""},{"year":1934,"event":"Elijah Muhammad assumes leadership; builds NOI as significant Black nationalist religious movement","severity":"neutral","source_url":""},{"year":1965,"event":"Malcolm X assassinated; three NOI members convicted","severity":"critical","source_url":""},{"year":1975,"event":"Elijah Muhammad dies; son Warith Deen Mohammed moves NOI toward mainstream Sunni Islam","severity":"high","source_url":""},{"year":1977,"event":"Farrakhan reorganizes the original NOI theology; builds parallel organization","severity":"high","source_url":""},{"year":1984,"event":"Farrakhan calls Judaism a 'gutter religion' and Hitler 'a very great man' — remarks documented nationally","severity":"critical","source_url":""},{"year":1995,"event":"Million Man March in Washington DC — hundreds of thousands attend event organized by Farrakhan","severity":"high","source_url":""},{"year":2018,"event":"Farrakhan compares Jewish people to termites; Facebook later removes him under dangerous individuals policy","severity":"critical","source_url":""},{"year":2021,"event":"Two of three men convicted of Malcolm X's murder exonerated; Manhattan DA investigation finds law enforcement failures","severity":"critical","source_url":"https://www.nytimes.com/2021/11/18/nyregion/malcolm-x-murder-exoneration.html"}],"community_impact":{"displacement":"Jewish Americans have been the primary documented targets of the NOI's sustained antisemitic ideology — an ideology that frames Jewish people as a malevolent controlling force in American life. The NOI's racial theology simultaneously targets white Americans as a devil race. Both have been documented by civil rights organizations as contributing to hate environments.","price_illusion":"The NOI presents as a Black liberation and self-determination organization — and has provided documented community infrastructure including schools, farms, and businesses in Black communities. This community service coexists with a documented hate ideology that the SPLC has designated a hate group.","tax_math":"The NOI's tax exemption as a religious organization means its operations — including its Final Call newspaper and business network — benefit from religious tax treatment. Donations to the NOI are received by a tax-exempt organization that the SPLC designates as a hate group.","wealth_velocity":"The NOI's business network — including Farrakhan's estimated personal wealth accumulated through the organization — represents wealth concentration in religious leadership consistent with the prosperity gospel pattern in Christianity."},"cost_absorption":{"who_benefited":[{"group":"Louis Farrakhan","how":"Maintained prominent national platform for 40+ years despite sustained documented antisemitism and hate group designation; relationships with politicians who met with him"}],"who_paid":[{"group":"Jewish Americans","how":"Sustained targeted antisemitism from one of America's most visible public figures; 'gutter religion,' 'termites,' 'Hitler was great'"},{"group":"Malcolm X","how":"Assassinated in 1965 by NOI members; two of three convicted men were exonerated in 2021"}],"the_gap":"Louis Farrakhan called Judaism a gutter religion in 1984. He called Hitler a very great man in 1984. He compared Jewish people to termites in 2018. The SPLC designates the Nation of Islam as a hate group. US Representatives have met with him and been documented in the photographs. Facebook removed him in 2019. He organized the Million Man March with hundreds of thousands of attendees. Three men were convicted of killing Malcolm X. Two were exonerated in 2021. The Manhattan DA found law enforcement had suppressed evidence."}});

w('profiles_v13','gulen-movement',{"brand_name":"Gülen Movement (Hizmet)","brand_slug":"gulen-movement","parent_company":"No formal organization — global network","ultimate_parent":"Fethullah Gülen (died 2024)","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"FETHULLAH GÜLEN LIVED IN PENNSYLVANIA FOR 25 YEARS WHILE TURKEY ACCUSED HIM OF RUNNING A PARALLEL STATE — HIS NETWORK OPERATED THE LARGEST CHAIN OF CHARTER SCHOOLS IN THE US AND PAID TEACHERS TO TRANSFER MONEY TO TURKEY","executive_summary":"The Gülen movement (also called Hizmet, meaning 'service') was an Islamic educational and civic movement founded by Turkish Islamic preacher Fethullah Gülen, who lived in self-imposed exile in Saylorsburg, Pennsylvania from 1999 until his death in October 2024. The movement's global network encompasses schools, media, businesses, and civic organizations across over 150 countries. In the United States, Gülen-affiliated organizations operated the largest single charter school network in the country — approximately 170 schools across 26 states, operating under names including Harmony, Magnolia, and Accord — with total federal and state funding exceeding $500 million annually. Federal investigators documented allegations of systematic visa fraud (using H-1B visas to import Turkish teachers), requiring teachers to transfer a portion of their salaries to movement-affiliated Turkish organizations ('golden generation' contributions), and bid-rigging in construction contracts at charter schools. Turkey designated the Gülen movement as the Fethullahist Terror Organization (FETÖ) following the 2016 coup attempt that Turkish authorities blamed on Gülen. The US government did not extradite Gülen before his death.","verdict_tags":["largest_charter_school_us_170_schools_26_states","500m_plus_annual_federal_state_funding","h1b_visa_fraud_allegations_documented","teacher_salary_transfer_golden_generation","turkey_feto_terrorist_designation","2016_coup_attempt_gulen_accused","extradition_refused_gulen_died_2024","bid_rigging_construction_investigations"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Federal and state investigators documented allegations that Turkish teachers employed at Gülen-affiliated charter schools under H-1B visas were required to contribute portions of their salaries to Gülen movement organizations — a form of salary kickback. Investigators found evidence of coordinated salary transfer schemes where teachers' net compensation was significantly less than their stated H-1B salaries. Some teachers were documented as having signed agreements to make these contributions as a condition of employment.","flags":["h1b_salary_kickback_documented_investigators","coordinated_transfer_scheme_evidence","teacher_agreement_condition_employment"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against Gülen-affiliated organizations have been identified.","flags":[],"sources":[]},"political":{"summary":"The Gülen movement's political significance is primarily the Turkey conflict. Turkish President Erdoğan blamed the July 2016 coup attempt — which killed approximately 250 people — on the Gülen movement, which he designated FETÖ. Turkey requested Gülen's extradition from the United States; the US consistently declined, citing insufficient evidence meeting extradition treaty standards. Gülen denied involvement. The US State Department listed the extradition request as ongoing. Gülen's charter school network's political connections — including documented lobbying expenditures and relationships with US politicians who visited Gülen or attended Gülen-affiliated events — were documented by journalists and investigators.","flags":["erdogan_feto_designation_2016_coup","250_killed_coup_attempt","us_extradition_refused_insufficient_evidence","charter_school_lobbying_politician_relationships_documented"],"sources":[]},"legal":{"summary":"Multiple federal and state investigations into Gülen-affiliated charter schools have documented: H-1B visa fraud (importing Turkish teachers who did not qualify for the visa category used); salary kickback schemes requiring teachers to transfer portions of pay to movement organizations; bid-rigging in school construction contracts; and improper financial relationships between charter schools and Gülen-affiliated vendors. No major criminal convictions of Gülen movement leaders in the US have been obtained. Civil settlements have been reached in some states. Texas's Harmony Public Schools (the largest single network) has been the subject of the most extensive documented investigations.","flags":["h1b_fraud_documented","salary_kickback_bid_rigging_documented","no_major_us_criminal_convictions","harmony_texas_most_investigated","civil_settlements_some_states"],"sources":[]},"tax":{"summary":"Gülen-affiliated charter schools receive hundreds of millions annually in federal and state funding as public charter schools — tax-funded institutions operating as private nonprofit entities. The salary kickback scheme — if the documented allegations are accurate — diverted a portion of taxpayer-funded teacher salaries to Turkish Islamic movement organizations. The charter school networks file Form 990 — their finances are publicly available.","flags":["500m_plus_annual_public_funding_tax","salary_kickback_diverted_public_funds_allegation","form_990_public_charter_networks"],"sources":[]},"executives":{"summary":"Fethullah Gülen lived in Saylorsburg, Pennsylvania from 1999 until his death on October 20, 2024 at age 83. He gave interviews, wrote books, and directed the global movement from his compound in Pennsylvania. His movement operated without a formal organizational structure — Gülen provided religious and intellectual guidance; local networks self-organized in each country. US charter school networks were led by local boards of Turkish-American educators with documented connections to the broader Gülen network.","flags":["gulen_died_october_2024","pennsylvania_compound_1999_2024","no_formal_organizational_structure","local_boards_turkish_american_documented_connections"],"sources":[]},"connections":{"summary":"The Gülen movement's global school network — operating in over 150 countries — represents one of the most extensive private Islamic educational enterprises in history. Its charter school network in the US was specifically designed to operate as public schools receiving government funding while promoting movement values and maintaining movement financial relationships. Gülen's death in October 2024 leaves the movement's future organizational direction uncertain.","flags":["150_countries_global_school_network","us_public_funding_private_values_documented","movement_future_uncertain_post_gulen"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Turkey has alleged that the Gülen movement organized and executed the 2016 coup attempt — killing approximately 250 people — and has documented what it characterizes as the movement's infiltration of the Turkish military, judiciary, police, and civil service over decades. Gülen and the movement denied involvement in the coup. US investigators have alleged that the charter school financial schemes were organized at the movement level rather than being local decisions — that the salary transfer system was a global movement structure applied to US charter school employees. Charter school boards have disputed that their schools were operationally directed by Gülen movement leadership.",
"flags":["2016_coup_execution_alleged_turkey","infiltration_military_judiciary_alleged","salary_scheme_movement_level_alleged_investigators","charter_boards_dispute_operational_direction"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against Gülen-affiliated organizations have been identified. The 2016 coup attempt in Turkey — which Turkey attributes to the Gülen movement — killed approximately 250 people, including civilians and security personnel. The movement denies responsibility.","flags":["2016_coup_250_killed_attributed_denied"],"sources":[]},"alternatives":{"cheaper":["Non-Gülen-affiliated charter schools without documented investigations","Traditional public schools without documented financial scheme allegations"],"healthier":["Charter schools with independent governance and no documented salary kickback allegations"],"diy":["The Texas Education Agency's investigations into Harmony Public Schools are documented in public records","Federal H-1B violation proceedings are public court records"]},"timeline":[{"year":1999,"event":"Fethullah Gülen relocates to Saylorsburg, Pennsylvania citing health reasons; Turkey later claims it was to direct coup planning","severity":"high","source_url":""},{"year":2000,"event":"Gülen-affiliated charter schools begin opening in the United States; network eventually reaches 170 schools in 26 states","severity":"high","source_url":""},{"year":2010,"event":"Federal investigations into H-1B visa use and salary transfer schemes at Gülen-affiliated charter schools begin","severity":"critical","source_url":""},{"year":2016,"event":"July: Military coup attempt in Turkey kills approximately 250 people; Erdoğan blames Gülen movement; designates FETÖ; requests extradition","severity":"critical","source_url":""},{"year":2016,"event":"US declines extradition citing insufficient evidence meeting treaty standards; Turkey relations deteriorate","severity":"critical","source_url":""},{"year":2024,"event":"October: Fethullah Gülen dies in Pennsylvania at age 83; movement's future direction uncertain","severity":"high","source_url":""}],"community_impact":{"displacement":"Students in Gülen-affiliated charter schools received public education funded by taxpayers while the schools' financial operations — salary kickbacks, H-1B visa schemes, bid-rigging — diverted portions of that public funding to an international Islamic movement. The quality of education provided by the schools has been documented as variable; some Harmony schools in Texas have received strong academic ratings.","price_illusion":"Gülen-affiliated charter schools presented as high-quality public schools emphasizing STEM education and civic engagement. The documented financial schemes — salary kickbacks, H-1B fraud, construction bid-rigging — operated beneath this public presentation.","tax_math":"Over $500 million annually in taxpayer funding flowed to Gülen-affiliated charter schools. The documented salary transfer scheme diverted portions of taxpayer-funded teacher salaries to Turkish movement organizations — an effective diversion of public funds to a foreign Islamic movement.","wealth_velocity":"The Gülen movement's global financial resources — accumulated through its school network, media, businesses, and donor base — are not publicly disclosed in any comprehensive way. The US charter school network's diversion of taxpayer funds to movement organizations represents a documented flow of public money into private movement resources."},"cost_absorption":{"who_benefited":[{"group":"Gülen movement globally","how":"Over $500M annual US taxpayer funding to charter schools; salary transfer scheme diverted additional funds to movement organizations; global network financed partly through US operations"}],"who_paid":[{"group":"US taxpayers","how":"Over $500M annually in public charter school funding; documented salary kickback scheme diverted portions to Turkish Islamic movement organizations"},{"group":"Turkish teachers on H-1B visas","how":"Required to transfer portions of salaries to movement organizations as condition of employment"}],"the_gap":"Fethullah Gülen lived in Pennsylvania for 25 years. His movement ran 170 charter schools in 26 states funded by over $500 million in US taxpayer money annually. Investigators documented that teachers were required to transfer portions of their salaries to movement organizations in Turkey. Turkey accused him of organizing a military coup that killed 250 people. The US refused to extradite him. He died in Pennsylvania in October 2024. The investigations found H-1B fraud and bid rigging. No major criminal convictions were obtained in the US."}});

w('profiles_v13','deobandi-movement',{"brand_name":"Deobandi Movement","brand_slug":"deobandi-movement","parent_company":"Multiple autonomous seminaries and organizations (sector profile)","ultimate_parent":"No central authority — sector analysis","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"THE DEOBANDI MOVEMENT PRODUCED THE TALIBAN — ITS PAKISTANI MADRASSA NETWORK EDUCATED MILLIONS OF STUDENTS IN A CURRICULUM WITH MINIMAL SECULAR CONTENT — AND DEOBANDI SCHOLARS ISSUED THE FATWA THAT JUSTIFIED SUICIDE BOMBING","executive_summary":"The Deobandi movement is a Sunni Islamic revivalist tradition founded in Deoband, India in 1867 — initially as a response to British colonialism, emphasizing strict adherence to Islamic law and rejection of Sufi practices and local religious syncretism. The Taliban — which governed Afghanistan 1996-2001 and has governed it again since 2021 — is a product of the Deobandi tradition, formed in Pakistani Deobandi madrassas in the 1990s. Pakistan's Deobandi seminary network — with an estimated 20,000+ madrassas — has educated millions of students in a curriculum critics document as providing minimal secular education while emphasizing religious texts. Deobandi scholars associated with Pakistani militant groups issued fatwas (religious rulings) justifying suicide bombing as a weapon against Western forces — a significant departure from traditional Islamic jurisprudence. Saudi Arabia has documented funding Deobandi madrassas as part of its broader anti-Iranian Sunni religious outreach, creating a documented intersection with the Saudi Wahhabi establishment.","verdict_tags":["taliban_deobandi_product_1990s_madrassas","minimal_secular_education_documented","suicide_bombing_fatwa_issued","saudi_funding_deobandi_madrassas_documented","20000_plus_pakistani_madrassas_estimated","taliban_1996_2001_governance","taliban_2021_return_governance","darul_uloom_deoband_founding_1867"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":true,"legal":true},"labor":{"summary":"Madrassa students in the Deobandi network receive room and board in exchange for religious study — a traditional Islamic educational model. Pakistani madrassa education has been documented to provide minimal or no secular vocational skills. Students who spend years in full-time madrassa education emerge with limited options in the secular Pakistani economy.","flags":["minimal_secular_vocational_training_documented","limited_secular_economy_options"],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for the Deobandi movement at the sector level.","flags":[],"sources":[]},"political":{"summary":"The Taliban's governance of Afghanistan — both 1996-2001 (ended by US invasion following 9/11) and 2021-present (following US withdrawal) — represents the most direct documented political consequence of the Deobandi movement. Taliban governance has documented: elimination of women's right to education and public life; execution of opponents; harboring of Al Qaeda (1996-2001); and systematic human rights violations. Pakistani Deobandi groups — including Jaish-e-Mohammed and Lashkar-e-Taiba (though the latter is more Ahl-e-Hadith) — have been designated terrorist organizations by the United States for attacks in India and Afghanistan.","flags":["taliban_deobandi_product_documented","women_education_eliminated_2021","al_qaeda_harbored_1996_2001","jaish_e_mohammed_designated_terrorist","pakistan_deobandi_militant_groups_documented"],"sources":[]},"legal":{"summary":"The Taliban is not universally designated as a terrorist organization by the United States — it is designated as a Specially Designated Global Terrorist entity but not under the formal FTO (Foreign Terrorist Organization) designation, a distinction that affected the US withdrawal negotiations. Al Qaeda — which operated from Taliban-governed Afghanistan — is designated FTO. Pakistani Deobandi militant groups including Jaish-e-Mohammed (responsible for the 2019 Pulwama attack killing 40 Indian security forces) are designated. Darul Uloom Deoband — the founding seminary — is not designated and has issued fatwas condemning terrorism, though other Deobandi scholars have issued contradictory rulings.","flags":["taliban_sdgt_not_fto","al_qaeda_fto_from_deobandi_Afghanistan","jaish_e_mohammed_fto_designated","pulwama_2019_40_killed","darul_uloom_deoband_not_designated_terrorism_condemnation_fatwa"],"sources":[]},"tax":{"summary":"Pakistani madrassas operate as religious educational institutions — many receiving public funding from the Pakistani government and documented Saudi funding — without the financial transparency standards of Western nonprofit organizations. The Deobandi movement's financial structure is extremely decentralized across thousands of autonomous seminaries.","flags":["pakistani_government_funding_documented","saudi_funding_documented","decentralized_no_transparency"],"sources":[]},"executives":{"summary":"The Deobandi movement has no central leadership. Darul Uloom Deoband — the founding seminary in Deoband, India — remains an influential institution whose scholarly positions are taken seriously across the movement. The Taliban's Supreme Leader — Haibatullah Akhundzada — leads from Kandahar and issues religious rulings governing Taliban-controlled Afghanistan. The Pakistani Deobandi political party Jamiat Ulema-e-Islam (JUI) is led by Fazlur Rehman — a documented political figure with relationships across Pakistani political parties.","flags":["no_central_leadership","akhundzada_taliban_supreme_leader","jui_fazlur_rehman_pakistan_politics"],"sources":[]},"connections":{"summary":"The 9/11 Commission documented Al Qaeda's presence in Taliban-governed Afghanistan and the Taliban's knowledge of bin Laden's operations. The Pakistani intelligence service (ISI) documented relationship with Deobandi militant groups has been a persistent source of US-Pakistan tension. Saudi funding for Pakistani Deobandi madrassas — documented in the context of the Saudi-Iran proxy competition — connects the Wahhabi and Deobandi traditions despite their theological differences.","flags":["9_11_commission_al_qaeda_taliban_documented","isi_militant_group_relationship_us_tension","saudi_funding_anti_iran_proxy_connection"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"US officials and researchers have alleged that Pakistan's ISI has maintained documented support for Deobandi militant groups — including the Haqqani Network and Afghan Taliban — as strategic assets against India and Afghanistan, while simultaneously cooperating with the US on counterterrorism. This 'double game' allegation has been documented by US officials including Secretary of State Hillary Clinton. Pakistan disputes the characterization.","flags":["isi_double_game_militant_support_alleged_clinton","haqqani_network_afghan_taliban_isi_assets_alleged","pakistan_disputes_characterization"],"sources":[]},"health_record":{"summary":"Taliban governance of Afghanistan 2021-present has eliminated women's access to secondary and higher education — affecting millions of Afghan girls and women. This represents a documented public health and human rights emergency specifically produced by a Deobandi-influenced governance system. Taliban public executions, amputations, and documented torture of opponents have been reported by multiple human rights organizations. The suicide bombing fatwas issued by some Deobandi scholars have contributed to documented mass casualty attacks in Afghanistan, Pakistan, and India.","flags":["women_education_eliminated_millions_affected_2021","public_execution_amputation_documented","suicide_bombing_fatwa_mass_casualty_attacks"],"sources":["https://www.hrw.org/tag/afghanistan"]},"alternatives":{"cheaper":["Mainstream Sunni Islamic education that does not produce documented militant movements","Secular Pakistani education that provides vocational skills alongside Islamic studies"],"healthier":["Islamic educational traditions that emphasize girls' education, civic participation, and secular skills"],"diy":["The 9/11 Commission Report documents Taliban-Al Qaeda connections extensively","Human Rights Watch's Afghanistan documentation is publicly available at hrw.org"]},"timeline":[{"year":1867,"event":"Darul Uloom Deoband founded in India — initially as anti-colonial Islamic revivalist institution","severity":"neutral","source_url":""},{"year":1980,"event":"Soviet invasion of Afghanistan; Pakistani madrassas absorb Afghan refugees; Deobandi curriculum expands; Saudi funding increases","severity":"high","source_url":""},{"year":1994,"event":"Taliban founded in Quetta-area Pakistani madrassas by Mullah Omar; draws on Deobandi students and theology","severity":"critical","source_url":""},{"year":1996,"event":"Taliban captures Kabul; establishes government; hosts Al Qaeda; bans women's education","severity":"critical","source_url":""},{"year":2001,"event":"US invasion following 9/11; Taliban regime falls; Al Qaeda connection documented","severity":"critical","source_url":""},{"year":2019,"event":"Jaish-e-Mohammed (Deobandi militant group) kills 40 Indian security forces in Pulwama attack; India-Pakistan crisis","severity":"critical","source_url":""},{"year":2021,"event":"US withdrawal; Taliban retakes Afghanistan; immediately bans women's secondary education","severity":"critical","source_url":""}],"community_impact":{"displacement":"Afghan women and girls — estimated 14+ million — have been displaced from educational participation since 2021 under Taliban governance rooted in Deobandi theology. Communities in Afghanistan, Pakistan, and India have absorbed the documented violence of Deobandi-influenced militant groups. The estimated 20,000+ Pakistani madrassas provide religious education to millions of students annually while providing minimal secular skills.","price_illusion":"The Deobandi movement presents as authentic Islamic revivalism — a return to core Islamic practice cleansed of local syncretism and colonial influence. Its political product in Afghanistan has eliminated women's education, conducted public executions, and harbored Al Qaeda.","tax_math":"Pakistani madrassas receive Pakistani government funding and documented Saudi funding while operating outside standard financial transparency frameworks. The financial support from external state sources — Saudi Arabia primarily — represents foreign funding of an educational system producing documented radicalization environments.","wealth_velocity":"The Deobandi movement's resources flow through thousands of autonomous madrassas without consolidated financial oversight. Saudi funding — directed at Deobandi institutions as part of the anti-Iranian Sunni outreach — represents documented external wealth injection into a decentralized educational network."},"cost_absorption":{"who_benefited":[{"group":"Taliban leadership","how":"Religious legitimacy from Deobandi tradition; governance of Afghanistan; sanctuary during 1996-2001 period enabled Al Qaeda 9/11 planning"}],"who_paid":[{"group":"Afghan women and girls","how":"Education eliminated under Taliban governance; 14+ million excluded from secondary and higher education since 2021"},{"group":"9/11 victims and their families","how":"Al Qaeda operations planned from Taliban-governed Afghanistan; Taliban-Al Qaeda relationship documented by 9/11 Commission"}],"the_gap":"The Taliban was founded in Pakistani Deobandi madrassas in 1994. It governed Afghanistan from 1996 to 2001 while hosting Al Qaeda. The 9/11 Commission documented the connection. The US invaded and removed the Taliban in 2001. The Taliban returned in 2021. The first thing they did was ban girls from secondary school. 14 million Afghan women and girls are now excluded from education. Pakistan's ISI has documented relationships with Deobandi militant groups. Saudi Arabia funds Deobandi madrassas. The cycle is documented."}});

w('profiles_v13','tablighi-jamaat',{"brand_name":"Tablighi Jamaat","brand_slug":"tablighi-jamaat","parent_company":"No formal organization","ultimate_parent":"Shura council (informal)","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"TABLIGHI JAMAAT IS THE WORLD'S LARGEST ISLAMIC MISSIONARY MOVEMENT WITH AN ESTIMATED 80 MILLION FOLLOWERS — THE FBI CALLED IT A 'GATEWAY TO TERRORISM' — AND SEVERAL CONVICTED TERRORISTS PASSED THROUGH ITS NETWORK","executive_summary":"Tablighi Jamaat (roughly translated: 'Society for Spreading Faith') is an Islamic missionary movement founded in India in 1927 by Muhammad Ilyas Kandhlawi. It is estimated to have 80-150 million followers globally — making it potentially the largest Islamic movement in the world. The organization operates through an entirely informal structure with no membership, no fees, no central organization, and no published accounts. Its central practice is the chilla — where members spend time traveling in groups to mosques, encouraging other Muslims to return to basic Islamic practice. The FBI has described Tablighi Jamaat as 'a gateway to terrorism' — a characterization the organization and mainstream scholars dispute. Several individuals who were later convicted of terrorism-related offenses — including Reid Shoe Bomber Richard Reid and Germaine Lindsay (7/7 London bombing) — had documented contact with Tablighi Jamaat before their radicalization. France banned Tablighi Jamaat from building what would have been Europe's largest mosque near Paris in 2020, citing security concerns. The organization is not designated as a terrorist organization by the United States or any major Western government.","verdict_tags":["80_150_million_followers_largest_islamic_movement","no_formal_organization_membership_fees","fbi_gateway_terrorism_characterization","richard_reid_germaine_lindsay_tablighi_contact","france_mosque_ban_security_2020","not_designated_terrorist_organization","chilla_practice_travel_mosques","india_1927_founding"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":false,"legal":false},"labor":{"summary":"Tablighi Jamaat has no employees and no formal organizational structure. Its members participate voluntarily, funding their own travel and time for chilla journeys. No labor violations have been identified.","flags":["no_employees_voluntary_participation","self_funded_travel"],"sources":[]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for Tablighi Jamaat.","flags":[],"sources":[]},"political":{"summary":"Tablighi Jamaat explicitly avoids political activity — its focus is personal religious practice and missionary outreach encouraging individual Muslims to observe prayer, dress, and other Islamic practices more strictly. This apolitical stance is genuine and consistent across its global network. France's security services have documented concerns that Tablighi Jamaat's insular networks and travel patterns create environments that have in some documented cases facilitated radicalization. The organization disputes that its practices contribute to radicalization, noting that its emphasis is on personal piety rather than political Islam.","flags":["explicitly_apolitical_genuine_documented","france_security_services_insular_networks_concern","organization_disputes_radicalization_contribution"],"sources":[]},"legal":{"summary":"Tablighi Jamaat is not designated as a terrorist organization by the United States, United Kingdom, European Union, or any major Western government. The FBI's 'gateway to terrorism' characterization has been disputed by academics who study the organization, who note that the vast majority of Tablighi Jamaat participants are not radicalized and that the correlation between Tablighi contact and later radicalization may reflect the organization's size rather than any causal mechanism. Richard Reid (Shoe Bomber, 2001) and Germaine Lindsay (7/7 London bombing, 2005) had documented contact with Tablighi Jamaat before their radicalization; neither was radicalized within Tablighi Jamaat's own networks per investigators.","flags":["not_designated_us_uk_eu","fbi_characterization_disputed_academics","reid_lindsay_contact_not_radicalized_within_tablighi","france_mosque_ban_security_2020"],"sources":[]},"tax":{"summary":"Tablighi Jamaat has no formal financial structure — members fund their own participation; local mosques where the organization operates are separately governed. No tax enforcement actions have been identified.","flags":["no_formal_financial_structure","member_self_funded"],"sources":[]},"executives":{"summary":"Tablighi Jamaat is governed by a shura (consultative council) based primarily at its Nizamuddin Markaz mosque in Delhi, India. The current senior leadership is drawn from the family of founder Muhammad Ilyas Kandhlawi. The organization's informal structure means 'executives' is a misnomer — it is more accurately described as a decentralized religious movement with recognized scholars providing guidance.","flags":["nizamuddin_markaz_delhi_center","kandhlawi_family_leadership","decentralized_scholars_guidance"],"sources":[]},"connections":{"summary":"Tablighi Jamaat's global network — operating in over 150 countries with an estimated 80-150 million participants — creates one of the most extensive informal religious social networks in the world. Its annual ijtemas (gatherings) in Bangladesh (Biswa Ijtema) and Pakistan attract millions of participants and are among the largest human gatherings on Earth. The organization's insular network — where members travel in groups, staying in mosques, interacting primarily with each other — has been documented by security services as creating information and travel patterns of interest.","flags":["150_countries_80_150m_participants","biswa_ijtema_millions_attendance","insular_network_security_services_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"French security services and some US counterterrorism officials have alleged that Tablighi Jamaat's networks — while not themselves recruiting for terrorism — create social environments and travel patterns that other organizations (particularly Al Qaeda-linked groups) have exploited for recruitment. The organization disputes this characterization and notes that its explicit theology rejects political violence. Academic researchers are divided on whether the documented cases of individuals with Tablighi contact later engaging in terrorism reflect organizational responsibility or simply the movement's massive scale.","flags":["exploitation_by_terrorist_recruiters_alleged_security_services","theology_rejects_political_violence","academic_division_organizational_responsibility"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against Tablighi Jamaat have been identified. A Tablighi Jamaat gathering in Malaysia in February-March 2020 was documented as a COVID-19 super-spreader event — one of the largest documented COVID clusters at the time, linked to thousands of cases across Southeast Asia. This was an inadvertent public health consequence of a large religious gathering rather than deliberate misconduct.","flags":["malaysia_2020_covid_super_spreader_thousands_cases","inadvertent_public_health_gathering"],"sources":[]},"alternatives":{"cheaper":["Mainstream mosque communities without documented security service concerns","Traditional Islamic education institutions with established academic frameworks"],"healthier":["Islamic organizations with transparent governance and published positions on political violence"],"diy":["Academic literature on Tablighi Jamaat — Yoginder Sikand's work is the most comprehensive — provides documented analysis","The organization's own publications are available in Islamic bookstores"]},"timeline":[{"year":1927,"event":"Muhammad Ilyas Kandhlawi founds Tablighi Jamaat in Mewat, India as a grassroots Islamic revivalist movement","severity":"neutral","source_url":""},{"year":1945,"event":"First international chilla journeys; movement begins global expansion","severity":"neutral","source_url":""},{"year":2001,"event":"Richard Reid (Shoe Bomber) had documented contact with Tablighi Jamaat before radicalization; FBI characterizes TJ as 'gateway to terrorism'","severity":"high","source_url":""},{"year":2005,"event":"Germaine Lindsay (7/7 London bombing) had documented Tablighi Jamaat contact; UK investigation examines network","severity":"high","source_url":""},{"year":2020,"event":"Tablighi Jamaat gathering in Kuala Lumpur documented as major COVID-19 super-spreader event — thousands of cases across Southeast Asia","severity":"high","source_url":""},{"year":2020,"event":"France bans Tablighi Jamaat from building Europe's largest mosque near Paris citing security concerns","severity":"high","source_url":""}],"community_impact":{"displacement":"The COVID-19 super-spreader event associated with the 2020 Kuala Lumpur gathering had documented public health consequences for Southeast Asian communities. Beyond this event, Tablighi Jamaat's primary documented impact is on Muslim communities globally where its conservative missionary approach has been documented to discourage engagement with secular society and reinforce gender segregation.","price_illusion":"Tablighi Jamaat presents as a purely apolitical personal piety movement — and by documented organizational intention, it is. The security services' concern is not about the organization itself but about its social networks being exploited by others.","tax_math":"Tablighi Jamaat has no financial structure — no fees, no accounts, no employees. Members fund their own participation. The mosques where it operates are separately governed and funded.","wealth_velocity":"The movement has no organizational wealth — which is both its most distinctive characteristic and a reason why standard financial accountability analysis does not apply."},"cost_absorption":{"who_benefited":[{"group":"Muslim communities globally","how":"Free religious outreach encouraging Islamic practice; social network across 150 countries"}],"who_paid":[{"group":"Southeast Asian communities","how":"COVID-19 super-spreader event from 2020 Kuala Lumpur gathering"}],"the_gap":"Tablighi Jamaat has 80-150 million participants. It has no membership, no fees, no organization, no accounts. The FBI called it a gateway to terrorism. Academics dispute this. Richard Reid and Germaine Lindsay had contact with Tablighi Jamaat before committing terrorism. Investigators found they were not radicalized within Tablighi's own network. France banned their mosque. The organization does not designate terrorism in any Western country. A gathering in Malaysia in 2020 became one of the largest COVID super-spreader events in history. The organization did not intend this."}});

w('profiles_v13','cair',{"brand_name":"Council on American-Islamic Relations (CAIR)","brand_slug":"cair","parent_company":"Council on American-Islamic Relations","ultimate_parent":"CAIR National Board","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"CAIR WAS NAMED AN UNINDICTED CO-CONSPIRATOR IN A FEDERAL HAMAS FUNDRAISING CASE — THE FBI CUT OFF FORMAL TIES IN 2009 — THEN RESTORED THEM — AND CAIR SAYS IT IS AMERICA'S LARGEST MUSLIM CIVIL RIGHTS ORGANIZATION","executive_summary":"The Council on American-Islamic Relations (CAIR) was founded in 1994 and describes itself as America's largest Muslim civil rights and advocacy organization, with chapters across the United States. CAIR's documented controversies center primarily on its 2007-2008 designation as an unindicted co-conspirator in the Holy Land Foundation case — the largest terrorism financing prosecution in US history, in which the Holy Land Foundation was convicted of funneling $12 million to Hamas. The federal government named CAIR as an unindicted co-conspirator without bringing charges against CAIR or proving that it had knowingly funded terrorism. CAIR disputed the designation and its legal basis. The FBI formally suspended its relationship with CAIR in 2009 citing the co-conspirator designation; that relationship was subsequently restored in some jurisdictions. Several CAIR founding board members have documented connections to the Muslim Brotherhood. CAIR maintains the co-conspirator designation was improper and that it has no operational ties to Hamas or the Muslim Brotherhood.","verdict_tags":["holy_land_foundation_unindicted_co_conspirator","fbi_suspended_relationship_2009","fbi_relationship_restored_some_jurisdictions","founding_board_muslim_brotherhood_connections_documented","cair_disputes_designation_no_charges_filed","largest_muslim_civil_rights_advocacy","civil_liberties_advocacy_documented","founding_1994"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":false,"legal":true},"labor":{"summary":"CAIR employs staff across its national and chapter offices. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for CAIR.","flags":[],"sources":[]},"political":{"summary":"CAIR engages in civil rights advocacy, litigation, and political lobbying on behalf of Muslim Americans. Documented activities: filing civil rights complaints against employment discrimination, airport profiling, and hate crimes; opposing the Trump travel ban; advocating against surveillance of Muslim communities; filing amicus briefs in religious freedom cases. CAIR has also been documented making statements about US foreign policy — particularly regarding Israel-Palestine — that have generated controversy and criticism from pro-Israel organizations. Some Republican politicians have called for designating CAIR as a terrorist organization; no US administration has done so.","flags":["civil_rights_complaints_discrimination_profiling","travel_ban_opposition","israel_palestine_statements_controversy","terrorist_designation_calls_not_acted_upon"],"sources":[]},"legal":{"summary":"Holy Land Foundation case (2007-2008): CAIR was named as one of approximately 300 unindicted co-conspirators in the prosecution of the Holy Land Foundation for Hamas fundraising. No charges were filed against CAIR. The Fifth Circuit Court of Appeals ruled in 2009 that the government had violated CAIR's due process rights by naming it as a co-conspirator without notice or opportunity to respond, but declined to order the name removed from public court filings. CAIR itself has never been charged with any terrorism-related offense. The FBI suspended formal communication with CAIR in 2009 following a Justice Department decision; relationships have varied by jurisdiction since then.","flags":["holy_land_unindicted_co_conspirator_no_charges","fifth_circuit_due_process_violation_found","no_terrorism_charges_ever_filed","fbi_suspended_2009_variable_since"],"sources":["https://www.justice.gov/archive/usao-ndtx/holyland.html"]},"tax":{"summary":"CAIR is a 501(c)(4) social welfare organization — contributions are not tax-deductible. Its affiliated CAIR Foundation is a 501(c)(3) — contributions are tax-deductible. CAIR files Form 990 — its finances are publicly available. Annual revenue is approximately $20-30 million.","flags":["501c4_contributions_not_deductible","cair_foundation_501c3_deductible","form_990_public","20_30m_annual_revenue"],"sources":[]},"executives":{"summary":"Nihad Awad has served as CAIR's executive director since its founding in 1994. Awad has been a prominent public voice for American Muslim civil rights. His documented statements — including a 1994 statement expressing support for Hamas before CAIR's founding — have been repeatedly cited by critics. Awad has said the statement was taken out of context and that he supports a two-state solution. Several CAIR founding board members — including Omar Ahmad — have documented connections to the Islamic Association for Palestine, which the government linked to the Muslim Brotherhood.","flags":["awad_executive_director_since_1994","awad_1994_hamas_statement_disputed_context","ahmad_islamic_association_palestine_connection"],"sources":[]},"connections":{"summary":"CAIR's critics document its founding connections to the Islamic Association for Palestine — which federal courts have found to be a front group for the Muslim Brotherhood's Palestine Committee — as evidence of organizational connection to Hamas. CAIR maintains these connections reflect its founders' backgrounds before CAIR's establishment, not organizational relationships. CAIR's civil rights work has generated documented partnerships with other civil rights organizations including the ACLU, NAACP, and various immigrant rights groups.","flags":["islamic_association_palestine_founding_connection","aclu_naacp_immigrant_rights_partnerships","critic_hamas_connection_vs_cair_rebuttal"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Critics — primarily from pro-Israel organizations and some counterterrorism researchers — have alleged that CAIR's founding connections to Brotherhood-linked organizations, combined with the unindicted co-conspirator designation, establish organizational ties to Hamas that CAIR has never severed. CAIR has disputed these allegations in detail, noting that no charges have ever been filed, that the co-conspirator designation violated its due process rights per the Fifth Circuit, and that its work is entirely focused on civil rights advocacy for Muslim Americans.","flags":["founding_brotherhood_connections_operational_ties_alleged_critics","cair_detailed_rebuttal","no_charges_fifth_circuit_due_process","civil_rights_work_documented"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against CAIR have been identified. CAIR's civil rights advocacy — including opposing discriminatory surveillance of Muslim communities and defending Muslim Americans' civil liberties — has documented positive community health dimensions for Muslim Americans experiencing discrimination.","flags":["civil_rights_advocacy_positive_community_dimension"],"sources":[]},"alternatives":{"cheaper":["Muslim Advocates — Muslim American civil rights organization with different founding history","Islamic Society of North America (ISNA) — largest Muslim American organization by membership"],"healthier":["Muslim American organizations without unindicted co-conspirator designations"],"diy":["CAIR's Form 990 is publicly available at ProPublica Nonprofit Explorer","The Holy Land Foundation trial documents are public court records","The Fifth Circuit opinion on CAIR's due process rights is public"]},"timeline":[{"year":1994,"event":"CAIR founded in Washington DC; Nihad Awad becomes executive director","severity":"neutral","source_url":""},{"year":2007,"event":"Federal government names CAIR as unindicted co-conspirator in Holy Land Foundation Hamas fundraising prosecution","severity":"critical","source_url":""},{"year":2008,"event":"Holy Land Foundation convicted on all counts; CAIR not charged with any offense","severity":"high","source_url":""},{"year":2009,"event":"FBI formally suspends relationship with CAIR following Justice Department decision; Fifth Circuit finds government violated CAIR's due process rights in co-conspirator naming","severity":"critical","source_url":""},{"year":2023,"event":"CAIR documents record Islamophobia complaints in the US; profile rises in context of Israel-Gaza conflict","severity":"high","source_url":""}],"community_impact":{"displacement":"Muslim Americans who have experienced employment discrimination, airport profiling, hate crimes, and civil rights violations have received documented assistance from CAIR's legal and advocacy work. The organization's civil rights record — regardless of its founding controversies — is documented.","price_illusion":"CAIR presents as a straightforward civil rights organization. The unindicted co-conspirator designation — which the Fifth Circuit found violated CAIR's due process rights — and the founding connections to Brotherhood-linked organizations create a documented controversy about the organization's full history that donors and constituents may not be aware of.","tax_math":"CAIR's 501(c)(4) structure means contributions are not tax-deductible — a limitation on its fundraising compared to 501(c)(3) organizations. Its affiliated CAIR Foundation's 501(c)(3) status allows deductible contributions for its research and education work.","wealth_velocity":"CAIR's $20-30 million annual revenue funds its national and chapter operations. Nihad Awad's compensation is disclosed through Form 990."},"cost_absorption":{"who_benefited":[{"group":"Muslim Americans experiencing civil rights violations","how":"CAIR's documented civil rights advocacy, legal representation, and complaint filing"}],"who_paid":[{"group":"CAIR's reputation","how":"Unindicted co-conspirator designation — even without charges and with Fifth Circuit due process finding — has damaged CAIR's relationships with law enforcement and some civil society partners"}],"the_gap":"CAIR was named an unindicted co-conspirator in the largest terrorism financing prosecution in US history. No charges were ever filed against CAIR. The Fifth Circuit found the government violated CAIR's due process rights in naming it. The FBI cut off formal relationships in 2009 and later restored some. CAIR has been doing civil rights work for Muslim Americans since 1994. Its founding board members had connections to organizations the government linked to the Muslim Brotherhood. CAIR disputes this means CAIR had operational ties to Hamas. The charges that would have resolved the question were never filed."}});

